import { useUndo } from './useUndo';

export default function App() {
  const [text, { set, undo, redo, canUndo, canRedo }] = useUndo('');

  return (
    <div style={{ padding: '2rem', display: 'flex', flexDirection: 'column', gap: '1rem', maxWidth: '32rem' }}>
      <textarea
        value={text}
        onChange={e => set(e.target.value)}
        style={{ width: '100%', height: '8rem', padding: '0.5rem', borderRadius: '0.375rem', border: '1px solid #d1d5db', fontFamily: 'inherit', fontSize: '0.875rem', resize: 'vertical' }}
        placeholder="Type something..."
      />
      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button onClick={undo} disabled={!canUndo} style={{ padding: '0.375rem 0.75rem', borderRadius: '0.375rem', border: '1px solid #d1d5db', cursor: canUndo ? 'pointer' : 'not-allowed', opacity: canUndo ? 1 : 0.4 }}>Undo</button>
        <button onClick={redo} disabled={!canRedo} style={{ padding: '0.375rem 0.75rem', borderRadius: '0.375rem', border: '1px solid #d1d5db', cursor: canRedo ? 'pointer' : 'not-allowed', opacity: canRedo ? 1 : 0.4 }}>Redo</button>
      </div>
      <p style={{ fontSize: '0.75rem', color: '#6b7280' }}>Characters: {text.length}</p>
    </div>
  );
}

